  1→/**
  2→ * Batch execution and dependency handling for sequant run.
  3→ *
  4→ * Contains functions for fetching issue metadata, parsing and sorting
  5→ * dependencies, splitting issues into batches, reading environment-based
  6→ * configuration, and orchestrating the execution of individual issues
  7→ * (including quality-loop retries, checkpoint commits, rebasing, and PR
  8→ * creation).
  9→ */
 10→
 11→import chalk from "chalk";
 12→import { spawnSync } from "child_process";
 13→import { LogWriter, createPhaseLogFromTiming } from "./log-writer.js";
 14→import { StateManager } from "./state-manager.js";
 15→import type { Phase as StatePhase } from "./state-schema.js";
 16→import { Phase, ExecutionConfig, PhaseResult, IssueResult } from "./types.js";
 17→import { ShutdownManager } from "../shutdown.js";
 18→import { PhaseSpinner } from "../phase-spinner.js";
 19→import { getGitDiffStats, getCommitHash } from "./git-diff-utils.js";
 20→import type { WorktreeInfo } from "./worktree-manager.js";
 21→import {
 22→  createCheckpointCommit,
 23→  rebaseBeforePR,
 24→  createPR,
 25→  readCacheMetrics,
 26→  filterResumedPhases,
 27→} from "./worktree-manager.js";
 28→import { executePhaseWithRetry } from "./phase-executor.js";
 29→import { parseQaVerdict, formatDuration } from "./phase-executor.js";
 30→import {
 31→  detectPhasesFromLabels,
 32→  parseRecommendedWorkflow,
 33→  determinePhasesForIssue,
 34→  hasUILabels,
 35→  BUG_LABELS,
 36→} from "./phase-mapper.js";
 37→
 38→export interface RunOptions {
 39→  phases?: string;
 40→  sequential?: boolean;
 41→  dryRun?: boolean;
 42→  verbose?: boolean;
 43→  timeout?: number;
 44→  logJson?: boolean;
 45→  noLog?: boolean;
 46→  logPath?: string;
 47→  qualityLoop?: boolean;
 48→  maxIterations?: number;
 49→  batch?: string[];
 50→  smartTests?: boolean;
 51→  noSmartTests?: boolean;
 52→  testgen?: boolean;
 53→  autoDetectPhases?: boolean;
 54→  /** Enable automatic worktree creation for issue isolation */
 55→  worktreeIsolation?: boolean;
 56→  /** Reuse existing worktrees instead of creating new ones */
 57→  reuseWorktrees?: boolean;
 58→  /** Suppress version warnings and non-essential output */
 59→  quiet?: boolean;
 60→  /** Chain issues: each branches from previous (requires --sequential) */
 61→  chain?: boolean;
 62→  /**
 63→   * Wait for QA pass before starting next issue in chain mode.
 64→   * When enabled, the chain pauses if QA fails, preventing downstream issues
 65→   * from building on potentially broken code.
 66→   */
 67→  qaGate?: boolean;
 68→  /**
 69→   * Base branch for worktree creation.
 70→   * Resolution priority: this CLI flag → settings.run.defaultBase → 'main'
 71→   */
 72→  base?: string;
 73→  /**
 74→   * Disable MCP servers in headless mode.
 75→   * When true, MCPs are not passed to the SDK (faster/cheaper runs).
 76→   * Resolution priority: this CLI flag → settings.run.mcp → default (true)
 77→   */
 78→  noMcp?: boolean;
 79→  /**
 80→   * Resume from last completed phase.
 81→   * Reads phase markers from GitHub issue comments and skips completed phases.
 82→   */
 83→  resume?: boolean;
 84→  /**
 85→   * Disable automatic retry with MCP fallback.
 86→   * When true, no retry attempts are made on phase failure.
 87→   * Useful for debugging to see the actual failure without retry masking it.
 88→   */
 89→  noRetry?: boolean;
 90→  /**
 91→   * Skip pre-PR rebase onto the base branch.
 92→   * When true, branches are not rebased before creating the PR.
 93→   * Use when you want to preserve branch state or handle rebasing manually.
 94→   */
 95→  noRebase?: boolean;
 96→  /**
 97→   * Skip PR creation after successful QA.
 98→   * When true, branches are pushed but no PR is created.
 99→   * Useful for manual workflows where PRs are created separately.
100→   */
101→  noPr?: boolean;
102→  /**
103→   * Force re-execution of issues even if they have completed status.
104→   * Bypasses the pre-flight state guard that skips ready_for_merge/merged issues.
105→   */
106→  force?: boolean;
107→  /**
108→   * Analyze run results and suggest workflow improvements.
109→   * Displays observations about timing patterns, phase mismatches, and
110→   * actionable suggestions after the summary output.
111→   */
112→  reflect?: boolean;
113→}
114→
115→export async function getIssueInfo(
116→  issueNumber: number,
117→): Promise<{ title: string; labels: string[] }> {
118→  try {
119→    const result = spawnSync(
120→      "gh",
121→      ["issue", "view", String(issueNumber), "--json", "title,labels"],
122→      { stdio: "pipe" },
123→    );
124→
125→    if (result.status === 0) {
126→      const data = JSON.parse(result.stdout.toString());
127→      return {
128→        title: data.title || `Issue #${issueNumber}`,
129→        labels: Array.isArray(data.labels)
130→          ? data.labels.map((l: { name: string }) => l.name)
131→          : [],
132→      };
133→    }
134→  } catch {
135→    // Ignore errors, use defaults
136→  }
137→
138→  return { title: `Issue #${issueNumber}`, labels: [] };
139→}
140→
141→/**
142→ * Parse dependencies from issue body and labels
143→ * Returns array of issue numbers this issue depends on
144→ */
145→export function parseDependencies(issueNumber: number): number[] {
146→  try {
147→    const result = spawnSync(
148→      "gh",
149→      ["issue", "view", String(issueNumber), "--json", "body,labels"],
150→      { stdio: "pipe" },
151→    );
152→
153→    if (result.status !== 0) return [];
154→
155→    const data = JSON.parse(result.stdout.toString());
156→    const dependencies: number[] = [];
157→
158→    // Parse from body: "Depends on: #123" or "**Depends on**: #123"
159→    if (data.body) {
160→      const bodyMatch = data.body.match(
161→        /\*?\*?depends\s+on\*?\*?:?\s*#?(\d+)/gi,
162→      );
163→      if (bodyMatch) {
164→        for (const match of bodyMatch) {
165→          const numMatch = match.match(/(\d+)/);
166→          if (numMatch) {
167→            dependencies.push(parseInt(numMatch[1], 10));
168→          }
169→        }
170→      }
171→    }
172→
173→    // Parse from labels: "depends-on/123" or "depends-on-123"
174→    if (data.labels && Array.isArray(data.labels)) {
175→      for (const label of data.labels) {
176→        const labelName = label.name || label;
177→        const labelMatch = labelName.match(/depends-on[-/](\d+)/i);
178→        if (labelMatch) {
179→          dependencies.push(parseInt(labelMatch[1], 10));
180→        }
181→      }
182→    }
183→
184→    return [...new Set(dependencies)]; // Remove duplicates
185→  } catch {
186→    return [];
187→  }
188→}
189→
190→/**
191→ * Sort issues by dependencies (topological sort)
192→ * Issues with no dependencies come first, then issues that depend on them
193→ */
194→export function sortByDependencies(issueNumbers: number[]): number[] {
195→  // Build dependency graph
196→  const dependsOn = new Map<number, number[]>();
197→  for (const issue of issueNumbers) {
198→    const deps = parseDependencies(issue);
199→    // Only include dependencies that are in our issue list
200→    dependsOn.set(
201→      issue,
202→      deps.filter((d) => issueNumbers.includes(d)),
203→    );
204→  }
205→
206→  // Topological sort using Kahn's algorithm
207→  const inDegree = new Map<number, number>();
208→  for (const issue of issueNumbers) {
209→    inDegree.set(issue, 0);
210→  }
211→  for (const deps of dependsOn.values()) {
212→    for (const dep of deps) {
213→      inDegree.set(dep, (inDegree.get(dep) || 0) + 1);
214→    }
215→  }
216→
217→  // Note: inDegree counts how many issues depend on each issue
218→  // We want to process issues that nothing depends on last
219→  // So we sort by: issues nothing depends on first, then dependent issues
220→  const sorted: number[] = [];
221→  const queue: number[] = [];
222→
223→  // Start with issues that have no dependencies
224→  for (const issue of issueNumbers) {
225→    const deps = dependsOn.get(issue) || [];
226→    if (deps.length === 0) {
227→      queue.push(issue);
228→    }
229→  }
230→
231→  const visited = new Set<number>();
232→  while (queue.length > 0) {
233→    const issue = queue.shift()!;
234→    if (visited.has(issue)) continue;
235→    visited.add(issue);
236→    sorted.push(issue);
237→
238→    // Find issues that depend on this one
239→    for (const [other, deps] of dependsOn.entries()) {
240→      if (deps.includes(issue) && !visited.has(other)) {
241→        // Check if all dependencies of 'other' are satisfied
242→        const allDepsSatisfied = deps.every((d) => visited.has(d));
243→        if (allDepsSatisfied) {
244→          queue.push(other);
245→        }
246→      }
247→    }
248→  }
249→
250→  // Add any remaining issues (circular dependencies or unvisited)
251→  for (const issue of issueNumbers) {
252→    if (!visited.has(issue)) {
253→      sorted.push(issue);
254→    }
255→  }
256→
257→  return sorted;
258→}
259→
260→/**
261→ * Parse batch arguments into groups of issues
262→ */
263→export function parseBatches(batchArgs: string[]): number[][] {
264→  return batchArgs.map((batch) =>
265→    batch
266→      .split(/\s+/)
267→      .map((n) => parseInt(n, 10))
268→      .filter((n) => !isNaN(n)),
269→  );
270→}
271→
272→/**
273→ * Parse environment variables for CI configuration
274→ */
275→export function getEnvConfig(): Partial<RunOptions> {
276→  const config: Partial<RunOptions> = {};
277→
278→  if (process.env.SEQUANT_QUALITY_LOOP === "true") {
279→    config.qualityLoop = true;
280→  }
281→
282→  if (process.env.SEQUANT_MAX_ITERATIONS) {
283→    const maxIter = parseInt(process.env.SEQUANT_MAX_ITERATIONS, 10);
284→    if (!isNaN(maxIter)) {
285→      config.maxIterations = maxIter;
286→    }
287→  }
288→
289→  if (process.env.SEQUANT_SMART_TESTS === "false") {
290→    config.noSmartTests = true;
291→  }
292→
293→  if (process.env.SEQUANT_TESTGEN === "true") {
294→    config.testgen = true;
295→  }
296→
297→  return config;
298→}
299→
300→export async function executeBatch(
301→  issueNumbers: number[],
302→  config: ExecutionConfig,
303→  logWriter: LogWriter | null,
304→  stateManager: StateManager | null,
305→  options: RunOptions,
306→  issueInfoMap: Map<number, { title: string; labels: string[] }>,
307→  worktreeMap: Map<number, WorktreeInfo>,
308→  shutdownManager?: ShutdownManager,
309→  packageManager?: string,
310→  baseBranch?: string,
311→): Promise<IssueResult[]> {
312→  const results: IssueResult[] = [];
313→
314→  for (const issueNumber of issueNumbers) {
315→    // Check if shutdown was triggered
316→    if (shutdownManager?.shuttingDown) {
317→      break;
318→    }
319→
320→    const issueInfo = issueInfoMap.get(issueNumber) ?? {
321→      title: `Issue #${issueNumber}`,
322→      labels: [],
323→    };
324→    const worktreeInfo = worktreeMap.get(issueNumber);
325→
326→    // Start issue logging
327→    if (logWriter) {
328→      logWriter.startIssue(issueNumber, issueInfo.title, issueInfo.labels);
329→    }
330→
331→    const result = await runIssueWithLogging(
332→      issueNumber,
333→      config,
334→      logWriter,
335→      stateManager,
336→      issueInfo.title,
337→      issueInfo.labels,
338→      options,
339→      worktreeInfo?.path,
340→      worktreeInfo?.branch,
341→      shutdownManager,
342→      false, // Batch mode doesn't support chain
343→      packageManager,
344→      undefined,
345→      baseBranch,
346→    );
347→    results.push(result);
348→
349→    // Record PR info in log before completing issue
350→    if (logWriter && result.prNumber && result.prUrl) {
351→      logWriter.setPRInfo(result.prNumber, result.prUrl);
352→    }
353→
354→    // Complete issue logging
355→    if (logWriter) {
356→      logWriter.completeIssue();
357→    }
358→  }
359→
360→  return results;
361→}
362→
363→export async function runIssueWithLogging(
364→  issueNumber: number,
365→  config: ExecutionConfig,
366→  logWriter: LogWriter | null,
367→  stateManager: StateManager | null,
368→  issueTitle: string,
369→  labels: string[],
370→  options: RunOptions,
371→  worktreePath?: string,
372→  branch?: string,
373→  shutdownManager?: ShutdownManager,
374→  chainMode?: boolean,
375→  packageManager?: string,
376→  isLastInChain?: boolean,
377→  baseBranch?: string,
378→): Promise<IssueResult> {
379→  const startTime = Date.now();
380→  const phaseResults: PhaseResult[] = [];
381→  let loopTriggered = false;
382→  let sessionId: string | undefined;
383→
384→  console.log(chalk.blue(`\n  Issue #${issueNumber}`));
385→  if (worktreePath) {
386→    console.log(chalk.gray(`    Worktree: ${worktreePath}`));
387→  }
388→
389→  // Initialize state tracking for this issue
390→  if (stateManager) {
391→    try {
392→      const existingState = await stateManager.getIssueState(issueNumber);
393→      if (!existingState) {
394→        await stateManager.initializeIssue(issueNumber, issueTitle, {
395→          worktree: worktreePath,
396→          branch,
397→          qualityLoop: config.qualityLoop,
398→          maxIterations: config.maxIterations,
399→        });
400→      } else {
401→        // Update worktree info if it changed
402→        if (worktreePath && branch) {
403→          await stateManager.updateWorktreeInfo(
404→            issueNumber,
405→            worktreePath,
406→            branch,
407→          );
408→        }
409→      }
410→    } catch (error) {
411→      // State tracking errors shouldn't stop execution
412→      if (config.verbose) {
413→        console.log(chalk.yellow(`    ⚠️  State tracking error: ${error}`));
414→      }
415→    }
416→  }
417→
418→  // Determine phases for this specific issue
419→  let phases: Phase[];
420→  let detectedQualityLoop = false;
421→  let specAlreadyRan = false;
422→
423→  if (options.autoDetectPhases) {
424→    // Check if labels indicate a simple bug/fix (skip spec entirely)
425→    const lowerLabels = labels.map((l) => l.toLowerCase());
426→    const isSimpleBugFix = lowerLabels.some((label) =>
427→      BUG_LABELS.some((bugLabel) => label.includes(bugLabel)),
428→    );
429→
430→    if (isSimpleBugFix) {
431→      // Simple bug fix: skip spec, go straight to exec → qa
432→      phases = ["exec", "qa"];
433→      console.log(chalk.gray(`    Bug fix detected: ${phases.join(" → ")}`));
434→    } else {
435→      // Run spec first to get recommended workflow
436→      console.log(chalk.gray(`    Running spec to determine workflow...`));
437→
438→      // Create spinner for spec phase (1 of estimated 3: spec, exec, qa)
439→      const specSpinner = new PhaseSpinner({
440→        phase: "spec",
441→        phaseIndex: 1,
442→        totalPhases: 3, // Estimate; will be refined after spec
443→        shutdownManager,
444→      });
445→      specSpinner.start();
446→
447→      // Track spec phase start in state
448→      if (stateManager) {
449→        try {
450→          await stateManager.updatePhaseStatus(
451→            issueNumber,
452→            "spec",
453→            "in_progress",
454→          );
455→        } catch {
456→          // State tracking errors shouldn't stop execution
457→        }
458→      }
459→
460→      const specStartTime = new Date();
461→      // Note: spec runs in main repo (not worktree) for planning
462→      const specResult = await executePhaseWithRetry(
463→        issueNumber,
464→        "spec",
465→        config,
466→        sessionId,
467→        worktreePath, // Will be ignored for spec (non-isolated phase)
468→        shutdownManager,
469→        specSpinner,
470→      );
471→      const specEndTime = new Date();
472→
473→      if (specResult.sessionId) {
474→        sessionId = specResult.sessionId;
475→        // Update session ID in state for resume capability
476→        if (stateManager) {
477→          try {
478→            await stateManager.updateSessionId(
479→              issueNumber,
480→              specResult.sessionId,
481→            );
482→          } catch {
483→            // State tracking errors shouldn't stop execution
484→          }
485→        }
486→      }
487→
488→      phaseResults.push(specResult);
489→      specAlreadyRan = true;
490→
491→      // Log spec phase result
492→      // Note: Spec runs in main repo, not worktree, so no git diff stats
493→      if (logWriter) {
494→        const phaseLog = createPhaseLogFromTiming(
495→          "spec",
496→          issueNumber,
497→          specStartTime,
498→          specEndTime,
499→          specResult.success
500→            ? "success"
501→            : specResult.error?.includes("Timeout")
502→              ? "timeout"
503→              : "failure",
504→          { error: specResult.error },
505→        );
506→        logWriter.logPhase(phaseLog);
507→      }
508→
509→      // Track spec phase completion in state
510→      if (stateManager) {
511→        try {
512→          const phaseStatus = specResult.success ? "completed" : "failed";
513→          await stateManager.updatePhaseStatus(
514→            issueNumber,
515→            "spec",
516→            phaseStatus,
517→            {
518→              error: specResult.error,
519→            },
520→          );
521→        } catch {
522→          // State tracking errors shouldn't stop execution
523→        }
524→      }
525→
526→      if (!specResult.success) {
527→        specSpinner.fail(specResult.error);
528→        const durationSeconds = (Date.now() - startTime) / 1000;
529→        return {
530→          issueNumber,
531→          success: false,
532→          phaseResults,
533→          durationSeconds,
534→          loopTriggered: false,
535→        };
536→      }
537→
538→      specSpinner.succeed();
539→
540→      // Parse recommended workflow from spec output
541→      const parsedWorkflow = specResult.output
542→        ? parseRecommendedWorkflow(specResult.output)
543→        : null;
544→
545→      if (parsedWorkflow) {
546→        // Remove spec from phases since we already ran it
547→        phases = parsedWorkflow.phases.filter((p) => p !== "spec");
548→        detectedQualityLoop = parsedWorkflow.qualityLoop;
549→        console.log(
550→          chalk.gray(
551→            `    Spec recommends: ${phases.join(" → ")}${detectedQualityLoop ? " (quality loop)" : ""}`,
552→          ),
553→        );
554→      } else {
555→        // Fall back to label-based detection
556→        console.log(
557→          chalk.yellow(
558→            `    Could not parse spec recommendation, using label-based detection`,
559→          ),
560→        );
561→        const detected = detectPhasesFromLabels(labels);
562→        phases = detected.phases.filter((p) => p !== "spec");
563→        detectedQualityLoop = detected.qualityLoop;
564→        console.log(chalk.gray(`    Fallback: ${phases.join(" → ")}`));
565→      }
566→    }
567→  } else {
568→    // Use explicit phases with adjustments
569→    phases = determinePhasesForIssue(config.phases, labels, options);
570→    if (phases.length !== config.phases.length) {
571→      console.log(chalk.gray(`    Phases adjusted: ${phases.join(" → ")}`));
572→    }
573→  }
574→
575→  // Resume: filter out completed phases if --resume flag is set
576→  if (options.resume) {
577→    const resumeResult = filterResumedPhases(issueNumber, phases, true);
578→    if (resumeResult.skipped.length > 0) {
579→      console.log(
580→        chalk.gray(
581→          `    Resume: skipping completed phases: ${resumeResult.skipped.join(", ")}`,
582→        ),
583→      );
584→      phases = resumeResult.phases;
585→    }
586→    // Also skip spec if it was auto-detected as completed
587→    if (
588→      specAlreadyRan &&
589→      resumeResult.skipped.length === 0 &&
590→      resumeResult.phases.length === 0
591→    ) {
592→      console.log(chalk.gray(`    Resume: all phases already completed`));
593→    }
594→  }
595→
596→  // Add testgen phase if requested (and spec was in the phases)
597→  if (
598→    options.testgen &&
599→    (phases.includes("spec") || specAlreadyRan) &&
600→    !phases.includes("testgen")
601→  ) {
602→    // Insert testgen at the beginning if spec already ran, otherwise after spec
603→    if (specAlreadyRan) {
604→      phases.unshift("testgen");
605→    } else {
606→      const specIndex = phases.indexOf("spec");
607→      if (specIndex !== -1) {
608→        phases.splice(specIndex + 1, 0, "testgen");
609→      }
610→    }
611→  }
612→
613→  let iteration = 0;
614→  const useQualityLoop = config.qualityLoop || detectedQualityLoop;
615→  const maxIterations = useQualityLoop ? config.maxIterations : 1;
616→  let completedSuccessfully = false;
617→
618→  while (iteration < maxIterations) {
619→    iteration++;
620→
621→    if (useQualityLoop && iteration > 1) {
622→      console.log(
623→        chalk.yellow(
624→          `    Quality loop iteration ${iteration}/${maxIterations}`,
625→        ),
626→      );
627→      loopTriggered = true;
628→    }
629→
630→    let phasesFailed = false;
631→
632→    // Calculate total phases for progress indicator
633→    // If spec already ran in auto-detect mode, it's counted separately
634→    const totalPhases = specAlreadyRan ? phases.length + 1 : phases.length;
635→    const phaseIndexOffset = specAlreadyRan ? 1 : 0;
636→
637→    for (let phaseIdx = 0; phaseIdx < phases.length; phaseIdx++) {
638→      const phase = phases[phaseIdx];
639→      const phaseNumber = phaseIdx + 1 + phaseIndexOffset;
640→
641→      // Create spinner for this phase
642→      const phaseSpinner = new PhaseSpinner({
643→        phase,
644→        phaseIndex: phaseNumber,
645→        totalPhases,
646→        shutdownManager,
647→        iteration: useQualityLoop ? iteration : undefined,
648→      });
649→      phaseSpinner.start();
650→
651→      // Track phase start in state
652→      if (stateManager) {
653→        try {
654→          await stateManager.updatePhaseStatus(
655→            issueNumber,
656→            phase as StatePhase,
657→            "in_progress",
658→          );
659→        } catch {
660→          // State tracking errors shouldn't stop execution
661→        }
662→      }
663→
664→      const phaseStartTime = new Date();
665→      const result = await executePhaseWithRetry(
666→        issueNumber,
667→        phase,
668→        config,
669→        sessionId,
670→        worktreePath,
671→        shutdownManager,
672→        phaseSpinner,
673→      );
674→      const phaseEndTime = new Date();
675→
676→      // Capture session ID for subsequent phases
677→      if (result.sessionId) {
678→        sessionId = result.sessionId;
679→        // Update session ID in state for resume capability
680→        if (stateManager) {
681→          try {
682→            await stateManager.updateSessionId(issueNumber, result.sessionId);
683→          } catch {
684→            // State tracking errors shouldn't stop execution
685→          }
686→        }
687→      }
688→
689→      phaseResults.push(result);
690→
691→      // Log phase result with observability data (AC-1, AC-2, AC-3, AC-7)
692→      if (logWriter) {
693→        // Capture git diff stats for worktree phases (AC-1, AC-3)
694→        const diffStats = worktreePath
695→          ? getGitDiffStats(worktreePath, baseBranch)
696→          : undefined;
697→
698→        // Capture commit hash after phase (AC-2)
699→        const commitHash = worktreePath
700→          ? getCommitHash(worktreePath)
701→          : undefined;
702→
703→        // Read cache metrics for QA phase (AC-7)
704→        const cacheMetrics =
705→          phase === "qa" ? readCacheMetrics(worktreePath) : undefined;
706→
707→        const phaseLog = createPhaseLogFromTiming(
708→          phase,
709→          issueNumber,
710→          phaseStartTime,
711→          phaseEndTime,
712→          result.success
713→            ? "success"
714→            : result.error?.includes("Timeout")
715→              ? "timeout"
716→              : "failure",
717→          {
718→            error: result.error,
719→            verdict: result.verdict,
720→            // Observability fields (AC-1, AC-2, AC-3, AC-7)
721→            filesModified: diffStats?.filesModified,
722→            fileDiffStats: diffStats?.fileDiffStats,
723→            commitHash,
724→            cacheMetrics,
725→          },
726→        );
727→        logWriter.logPhase(phaseLog);
728→      }
729→
730→      // Track phase completion in state
731→      if (stateManager) {
732→        try {
733→          const phaseStatus = result.success
734→            ? "completed"
735→            : result.error?.includes("Timeout")
736→              ? "failed"
737→              : "failed";
738→          await stateManager.updatePhaseStatus(
739→            issueNumber,
740→            phase as StatePhase,
741→            phaseStatus,
742→            { error: result.error },
743→          );
744→        } catch {
745→          // State tracking errors shouldn't stop execution
746→        }
747→      }
748→
749→      if (result.success) {
750→        phaseSpinner.succeed();
751→      } else {
752→        phaseSpinner.fail(result.error);
753→        phasesFailed = true;
754→
755→        // If quality loop enabled, run loop phase to fix issues
756→        if (useQualityLoop && iteration < maxIterations) {
757→          // Create spinner for loop phase
758→          const loopSpinner = new PhaseSpinner({
759→            phase: "loop",
760→            phaseIndex: phaseNumber,
761→            totalPhases,
762→            shutdownManager,
763→            iteration,
764→          });
765→          loopSpinner.start();
766→
767→          const loopResult = await executePhaseWithRetry(
768→            issueNumber,
769→            "loop",
770→            config,
771→            sessionId,
772→            worktreePath,
773→            shutdownManager,
774→            loopSpinner,
775→          );
776→          phaseResults.push(loopResult);
777→
778→          if (loopResult.sessionId) {
779→            sessionId = loopResult.sessionId;
780→          }
781→
782→          if (loopResult.success) {
783→            loopSpinner.succeed();
784→            // Continue to next iteration
785→            break;
786→          } else {
787→            loopSpinner.fail(loopResult.error);
788→          }
789→        }
790→
791→        // Stop on first failure (if not in quality loop or loop failed)
792→        break;
793→      }
794→    }
795→
796→    // If all phases passed, exit the loop
797→    if (!phasesFailed) {
798→      completedSuccessfully = true;
799→      break;
800→    }
801→
802→    // If we're not in quality loop mode, don't retry
803→    if (!config.qualityLoop) {
804→      break;
805→    }
806→  }
807→
808→  const durationSeconds = (Date.now() - startTime) / 1000;
809→  // Success is determined by whether all phases completed in any iteration,
810→  // not whether all accumulated phase results passed (which would fail after loop recovery)
811→  const success = completedSuccessfully;
812→
813→  // Update final issue status in state
814→  if (stateManager) {
815→    try {
816→      const finalStatus = success ? "ready_for_merge" : "in_progress";
817→      await stateManager.updateIssueStatus(issueNumber, finalStatus);
818→    } catch {
819→      // State tracking errors shouldn't stop execution
820→    }
821→  }
822→
823→  // Create checkpoint commit in chain mode after QA passes
824→  if (success && chainMode && worktreePath) {
825→    createCheckpointCommit(worktreePath, issueNumber, config.verbose);
826→  }
827→
828→  // Rebase onto the base branch before PR creation (unless --no-rebase)
829→  // This ensures the branch is up-to-date and prevents lockfile drift
830→  // AC-1: Non-chain mode rebases onto the base branch before PR
831→  // AC-2: Chain mode rebases only the final branch onto the base branch before PR
832→  //        (intermediate branches must stay based on their predecessor)
833→  const shouldRebase =
834→    success &&
835→    worktreePath &&
836→    !options.noRebase &&
837→    (!chainMode || isLastInChain);
838→  if (shouldRebase) {
839→    rebaseBeforePR(
840→      worktreePath,
841→      issueNumber,
842→      packageManager,
843→      config.verbose,
844→      baseBranch,
845→    );
846→  }
847→
848→  // Create PR after successful QA + rebase (unless --no-pr)
849→  let prNumber: number | undefined;
850→  let prUrl: string | undefined;
851→  const shouldCreatePR = success && worktreePath && branch && !options.noPr;
852→  if (shouldCreatePR) {
853→    const prResult = createPR(
854→      worktreePath,
855→      issueNumber,
856→      issueTitle,
857→      branch,
858→      config.verbose,
859→      labels,
860→    );
861→    if (prResult.success && prResult.prNumber && prResult.prUrl) {
862→      prNumber = prResult.prNumber;
863→      prUrl = prResult.prUrl;
864→
865→      // Update workflow state with PR info
866→      if (stateManager) {
867→        try {
868→          await stateManager.updatePRInfo(issueNumber, {
869→            number: prResult.prNumber,
870→            url: prResult.prUrl,
871→          });
872→        } catch {
873→          // State tracking errors shouldn't stop execution
874→        }
875→      }
876→    }
877→  }
878→
879→  return {
880→    issueNumber,
881→    success,
882→    phaseResults,
883→    durationSeconds,
884→    loopTriggered,
885→    prNumber,
886→    prUrl,
887→  };
888→}
