102→ */
103→export async function runCommand(
104→  issues: string[],
105→  options: RunOptions,
106→): Promise<void> {
107→  console.log(ui.headerBox("SEQUANT WORKFLOW"));
108→
109→  // Version freshness check (cached, non-blocking, respects --quiet)
