137→  const envConfig = getEnvConfig();
138→
139→  // Settings provide defaults, env overrides settings, CLI overrides all
140→  // Note: phases are auto-detected per-issue unless --phases is explicitly set
141→  // Commander.js converts --no-X to { X: false }, not { noX: true }.
142→  // Normalize these so RunOptions fields (noLog, noMcp, etc.) work correctly.
143→  // eslint-disable-next-line @typescript-eslint/no-explicit-any
144→  const cliOpts = options as any;
145→  const normalizedOptions: RunOptions = {
146→    ...options,
147→    ...(cliOpts.log === false && { noLog: true }),
148→    ...(cliOpts.smartTests === false && { noSmartTests: true }),
149→    ...(cliOpts.mcp === false && { noMcp: true }),
150→    ...(cliOpts.retry === false && { noRetry: true }),
151→    ...(cliOpts.rebase === false && { noRebase: true }),
152→    ...(cliOpts.pr === false && { noPr: true }),
153→  };
