157→    sequential: normalizedOptions.sequential ?? settings.run.sequential,
158→    timeout: normalizedOptions.timeout ?? settings.run.timeout,
159→    logPath: normalizedOptions.logPath ?? settings.run.logPath,
160→    qualityLoop: normalizedOptions.qualityLoop ?? settings.run.qualityLoop,
161→    maxIterations:
162→      normalizedOptions.maxIterations ?? settings.run.maxIterations,
163→    noSmartTests: normalizedOptions.noSmartTests ?? !settings.run.smartTests,
164→    // Env overrides
165→    ...envConfig,
166→    // CLI explicit options override all
167→    ...normalizedOptions,
168→  };
169→
170→  // Determine if we should auto-detect phases from labels
171→  const autoDetectPhases = !options.phases && settings.run.autoDetectPhases;
172→  mergedOptions.autoDetectPhases = autoDetectPhases;
173→
174→  // Resolve base branch: CLI flag → settings.run.defaultBase → auto-detect → 'main'
175→  const resolvedBaseBranch =
176→    options.base ??
177→    settings.run.defaultBase ??
178→    detectDefaultBranch(mergedOptions.verbose ?? false);
179→
180→  // Parse issue numbers (or use batch mode)
181→  let issueNumbers: number[];
182→  let batches: number[][] | null = null;
183→
184→  if (mergedOptions.batch && mergedOptions.batch.length > 0) {
185→    batches = parseBatches(mergedOptions.batch);
186→    issueNumbers = batches.flat();
187→    console.log(
188→      chalk.gray(
189→        `  Batch mode: ${batches.map((b) => `[${b.join(", ")}]`).join(" → ")}`,
190→      ),
191→    );
192→  } else {
193→    issueNumbers = issues.map((i) => parseInt(i, 10)).filter((n) => !isNaN(n));
194→  }
195→
196→  if (issueNumbers.length === 0) {
197→    console.log(chalk.red("❌ No valid issue numbers provided."));
198→    console.log(chalk.gray("\nUsage: npx sequant run <issues...> [options]"));
199→    console.log(chalk.gray("Example: npx sequant run 1 2 3 --sequential"));
200→    console.log(
201→      chalk.gray('Batch example: npx sequant run --batch "1 2" --batch "3"'),
202→    );
203→    console.log(
204→      chalk.gray("Chain example: npx sequant run 1 2 3 --sequential --chain"),
205→    );
206→    return;
207→  }
208→
209→  // Validate chain mode requirements
210→  if (mergedOptions.chain) {
211→    if (!mergedOptions.sequential) {
212→      console.log(chalk.red("❌ --chain requires --sequential flag"));
213→      console.log(
214→        chalk.gray(
215→          "   Chain mode executes issues sequentially, each branching from the previous.",
216→        ),
217→      );
218→      console.log(
219→        chalk.gray("   Usage: npx sequant run 1 2 3 --sequential --chain"),
