223→
224→    if (batches) {
225→      console.log(chalk.red("❌ --chain cannot be used with --batch"));
226→      console.log(
227→        chalk.gray(
228→          "   Chain mode creates a linear dependency chain between issues.",
229→        ),
230→      );
231→      return;
232→    }
233→
234→    // Warn about long chains
235→    if (issueNumbers.length > 5) {
236→      console.log(
237→        chalk.yellow(
238→          `  ⚠️  Warning: Chain has ${issueNumbers.length} issues (recommended max: 5)`,
239→        ),
240→      );
241→      console.log(
242→        chalk.yellow(
243→          "     Long chains increase merge complexity and review difficulty.",
244→        ),
245→      );
246→      console.log(
247→        chalk.yellow(
248→          "     Consider breaking into smaller chains or using batch mode.",
249→        ),
250→      );
251→      console.log("");
252→    }
253→  }
