274→    issueNumbers = sortByDependencies(issueNumbers);
275→    const orderChanged = !originalOrder.every((n, i) => n === issueNumbers[i]);
276→    if (orderChanged) {
277→      console.log(
278→        chalk.gray(
279→          `  Dependency order: ${issueNumbers.map((n) => `#${n}`).join(" → ")}`,
280→        ),
281→      );
282→    }
283→  }
284→
285→  // Build config
