289→    : null;
290→
291→  // Determine MCP enablement: CLI flag (--no-mcp) → settings.run.mcp → default (true)
292→  const mcpEnabled = mergedOptions.noMcp
293→    ? false
294→    : (settings.run.mcp ?? DEFAULT_CONFIG.mcp);
295→
296→  // Resolve retry setting: CLI flag → settings.run.retry → default (true)
297→  const retryEnabled = mergedOptions.noRetry
298→    ? false
299→    : (settings.run.retry ?? true);
300→
301→  const config: ExecutionConfig = {
302→    ...DEFAULT_CONFIG,
303→    phases: explicitPhases ?? DEFAULT_PHASES,
304→    sequential: mergedOptions.sequential ?? false,
305→    dryRun: mergedOptions.dryRun ?? false,
306→    verbose: mergedOptions.verbose ?? false,
307→    phaseTimeout: mergedOptions.timeout ?? DEFAULT_CONFIG.phaseTimeout,
308→    qualityLoop: mergedOptions.qualityLoop ?? false,
309→    maxIterations: mergedOptions.maxIterations ?? DEFAULT_CONFIG.maxIterations,
310→    noSmartTests: mergedOptions.noSmartTests ?? false,
311→    mcp: mcpEnabled,
312→    retry: retryEnabled,
313→  };
314→
315→  // Propagate verbose mode to UI config so spinners use text-only mode.
316→  // This prevents animated spinner control characters from colliding with
317→  // verbose console.log() calls from StateManager/MetricsWriter (#282).
318→  if (config.verbose) {
319→    ui.configure({ verbose: true });
320→  }
321→
322→  // Initialize log writer if JSON logging enabled
323→  // Default: enabled via settings (logJson: true), can be disabled with --no-log
324→  let logWriter: LogWriter | null = null;
325→  const shouldLog =
326→    !mergedOptions.noLog &&
327→    !config.dryRun &&
328→    (mergedOptions.logJson ?? settings.run.logJson);
329→
330→  if (shouldLog) {
331→    const runConfig: RunConfig = {
332→      phases: config.phases,
333→      sequential: config.sequential,
334→      qualityLoop: config.qualityLoop,
335→      maxIterations: config.maxIterations,
336→      chain: mergedOptions.chain,
337→      qaGate: mergedOptions.qaGate,
338→    };
339→
340→    try {
341→      logWriter = new LogWriter({
342→        logPath: mergedOptions.logPath ?? settings.run.logPath,
343→        verbose: config.verbose,
344→        startCommit: getCommitHash(process.cwd()),
345→      });
346→      await logWriter.initialize(runConfig);
347→    } catch (err) {
348→      // Log initialization failure is non-fatal - warn and continue without logging
349→      // Common causes: permissions issues, disk full, invalid path
350→      const errorMessage = err instanceof Error ? err.message : String(err);
351→      console.log(
352→        chalk.yellow(
353→          `  ⚠️ Log initialization failed, continuing without logging: ${errorMessage}`,
354→        ),
355→      );
356→      logWriter = null;
357→    }
358→  }
359→
360→  // Initialize state manager for persistent workflow state tracking
361→  // State tracking is always enabled (unless dry run)
362→  let stateManager: StateManager | null = null;
363→  if (!config.dryRun) {
364→    stateManager = new StateManager({ verbose: config.verbose });
365→  }
366→
367→  // Initialize shutdown manager for graceful interruption handling
368→  const shutdown = new ShutdownManager();
369→
370→  // Register log writer finalization as cleanup task
371→  if (logWriter) {
372→    const writer = logWriter; // Capture for closure
373→    shutdown.registerCleanup("Finalize run logs", async () => {
374→      await writer.finalize();
375→    });
376→  }
377→
378→  // Display configuration
379→  console.log(chalk.gray(`  Stack: ${manifest.stack}`));
380→  if (autoDetectPhases) {
381→    console.log(chalk.gray(`  Phases: auto-detect from labels`));
382→  } else {
383→    console.log(chalk.gray(`  Phases: ${config.phases.join(" → ")}`));
384→  }
385→  console.log(
386→    chalk.gray(
387→      `  Mode: ${config.sequential ? "stop-on-failure" : "continue-on-failure"}`,
388→    ),
389→  );
390→  if (config.qualityLoop) {
391→    console.log(
392→      chalk.gray(
393→        `  Quality loop: enabled (max ${config.maxIterations} iterations)`,
394→      ),
395→    );
396→  }
397→  if (mergedOptions.testgen) {
398→    console.log(chalk.gray(`  Testgen: enabled`));
399→  }
400→  if (config.noSmartTests) {
401→    console.log(chalk.gray(`  Smart tests: disabled`));
402→  }
403→  if (config.dryRun) {
404→    console.log(chalk.yellow(`  ⚠️  DRY RUN - no actual execution`));
405→  }
406→  if (logWriter) {
407→    console.log(
408→      chalk.gray(
409→        `  Logging: JSON (run ${logWriter.getRunId()?.slice(0, 8)}...)`,
410→      ),
411→    );
412→  }
413→  if (stateManager) {
414→    console.log(chalk.gray(`  State tracking: enabled`));
415→  }
416→  if (mergedOptions.force) {
417→    console.log(chalk.yellow(`  Force mode: enabled (bypass state guard)`));
418→  }
419→  console.log(
420→    chalk.gray(`  Issues: ${issueNumbers.map((n) => `#${n}`).join(", ")}`),
421→  );
422→
423→  // ============================================================================
424→  // Pre-flight State Guard (#305)
425→  // ============================================================================
426→
427→  // AC-5: Auto-cleanup at run start - reconcile stale ready_for_merge states
428→  if (stateManager && !config.dryRun) {
429→    try {
430→      const reconcileResult = await reconcileStateAtStartup({
431→        verbose: config.verbose,
432→      });
433→
434→      if (reconcileResult.success && reconcileResult.advanced.length > 0) {
435→        console.log(
436→          chalk.gray(
437→            `  State reconciled: ${reconcileResult.advanced.map((n) => `#${n}`).join(", ")} → merged`,
438→          ),
439→        );
440→      }
441→    } catch {
442→      // AC-8: Graceful degradation - don't block execution on reconciliation failure
443→      if (config.verbose) {
444→        console.log(
445→          chalk.yellow(`  ⚠️  State reconciliation failed, continuing...`),
446→        );
447→      }
448→    }
449→  }
450→
451→  // AC-1 & AC-2: Pre-flight state guard - skip completed issues unless --force
452→  if (stateManager && !config.dryRun && !mergedOptions.force) {
453→    const skippedIssues: number[] = [];
454→    const activeIssues: number[] = [];
455→
456→    for (const issueNumber of issueNumbers) {
457→      try {
458→        const issueState = await stateManager.getIssueState(issueNumber);
459→        if (
460→          issueState &&
461→          (issueState.status === "ready_for_merge" ||
462→            issueState.status === "merged")
463→        ) {
464→          skippedIssues.push(issueNumber);
465→          console.log(
466→            chalk.yellow(
467→              `  ⚠️  #${issueNumber}: already ${issueState.status} — skipping (use --force to re-run)`,
468→            ),
469→          );
470→        } else {
471→          activeIssues.push(issueNumber);
472→        }
473→      } catch {
474→        // AC-8: Graceful degradation - if state check fails, include the issue
475→        activeIssues.push(issueNumber);
476→      }
477→    }
478→
479→    // Update issueNumbers to only include active issues
480→    if (skippedIssues.length > 0) {
481→      issueNumbers = activeIssues;
482→
483→      if (issueNumbers.length === 0) {
484→        console.log(
485→          chalk.yellow(
486→            `\n  All issues already completed. Use --force to re-run.`,
487→          ),
488→        );
489→        return;
490→      }
491→
492→      console.log(
493→        chalk.gray(
494→          `  Active issues: ${issueNumbers.map((n) => `#${n}`).join(", ")}`,
495→        ),
496→      );
497→    }
498→  }
499→
500→  // Worktree isolation is enabled by default for multi-issue runs
501→  const useWorktreeIsolation =
502→    mergedOptions.worktreeIsolation !== false && issueNumbers.length > 0;
503→
504→  if (useWorktreeIsolation) {
505→    console.log(chalk.gray(`  Worktree isolation: enabled`));
506→  }
507→  if (resolvedBaseBranch) {
508→    console.log(chalk.gray(`  Base branch: ${resolvedBaseBranch}`));
509→  }
510→  if (mergedOptions.chain) {
511→    console.log(
512→      chalk.gray(`  Chain mode: enabled (each issue branches from previous)`),
513→    );
514→  }
515→  if (mergedOptions.qaGate) {
516→    console.log(chalk.gray(`  QA gate: enabled (chain waits for QA pass)`));
517→  }
518→
519→  // Fetch issue info for all issues first
520→  const issueInfoMap = new Map<number, { title: string; labels: string[] }>();
521→  for (const issueNumber of issueNumbers) {
522→    issueInfoMap.set(issueNumber, await getIssueInfo(issueNumber));
523→  }
524→
525→  // Create worktrees for all issues before execution (if isolation enabled)
526→  let worktreeMap: Map<number, WorktreeInfo> = new Map();
527→  if (useWorktreeIsolation && !config.dryRun) {
528→    const issueData = issueNumbers.map((num) => ({
529→      number: num,
530→      title: issueInfoMap.get(num)?.title || `Issue #${num}`,
531→    }));
532→
533→    // Use chain mode or standard worktree creation
534→    if (mergedOptions.chain) {
535→      worktreeMap = await ensureWorktreesChain(
536→        issueData,
537→        config.verbose,
538→        manifest.packageManager,
539→        resolvedBaseBranch,
540→      );
541→    } else {
542→      worktreeMap = await ensureWorktrees(
543→        issueData,
544→        config.verbose,
545→        manifest.packageManager,
546→        resolvedBaseBranch,
547→      );
548→    }
549→
550→    // Register cleanup tasks for newly created worktrees (not pre-existing ones)
551→    for (const [issueNum, worktree] of worktreeMap.entries()) {
552→      if (!worktree.existed) {
553→        shutdown.registerCleanup(
554→          `Cleanup worktree for #${issueNum}`,
555→          async () => {
556→            // Remove worktree (leaves branch intact for recovery)
557→            const result = spawnSync(
558→              "git",
559→              ["worktree", "remove", "--force", worktree.path],
560→              {
561→                stdio: "pipe",
562→              },
563→            );
564→            if (result.status !== 0 && config.verbose) {
565→              console.log(
566→                chalk.yellow(
567→                  `    Warning: Could not remove worktree ${worktree.path}`,
568→                ),
569→              );
570→            }
571→          },
572→        );
573→      }
574→    }
575→  }
576→
577→  // Execute with graceful shutdown handling
578→  const results: IssueResult[] = [];
579→  let exitCode = 0;
580→
581→  try {
582→    if (batches) {
583→      // Batch execution: run batches sequentially, issues within batch based on mode
584→      for (let batchIdx = 0; batchIdx < batches.length; batchIdx++) {
585→        const batch = batches[batchIdx];
586→        console.log(
587→          chalk.blue(
588→            `\n  Batch ${batchIdx + 1}/${batches.length}: Issues ${batch.map((n) => `#${n}`).join(", ")}`,
589→          ),
590→        );
591→
592→        const batchResults = await executeBatch(
593→          batch,
594→          config,
595→          logWriter,
596→          stateManager,
597→          mergedOptions,
598→          issueInfoMap,
599→          worktreeMap,
600→          shutdown,
601→          manifest.packageManager,
602→          resolvedBaseBranch,
603→        );
604→        results.push(...batchResults);
605→
606→        // Check if batch failed and we should stop
607→        const batchFailed = batchResults.some((r) => !r.success);
608→        if (batchFailed && config.sequential) {
609→          console.log(
610→            chalk.yellow(
611→              `\n  ⚠️  Batch ${batchIdx + 1} failed, stopping batch execution`,
612→            ),
613→          );
614→          break;
615→        }
616→      }
617→    } else if (config.sequential) {
618→      // Sequential execution
619→      for (let i = 0; i < issueNumbers.length; i++) {
620→        const issueNumber = issueNumbers[i];
621→        const issueInfo = issueInfoMap.get(issueNumber) ?? {
622→          title: `Issue #${issueNumber}`,
623→          labels: [],
624→        };
625→        const worktreeInfo = worktreeMap.get(issueNumber);
626→
627→        // Start issue logging
628→        if (logWriter) {
629→          logWriter.startIssue(issueNumber, issueInfo.title, issueInfo.labels);
630→        }
631→
632→        const result = await runIssueWithLogging(
633→          issueNumber,
634→          config,
635→          logWriter,
636→          stateManager,
637→          issueInfo.title,
638→          issueInfo.labels,
639→          mergedOptions,
640→          worktreeInfo?.path,
641→          worktreeInfo?.branch,
642→          shutdown,
643→          mergedOptions.chain, // Enable checkpoint commits in chain mode
644→          manifest.packageManager,
645→          // In chain mode, only the last issue should trigger pre-PR rebase
646→          mergedOptions.chain ? i === issueNumbers.length - 1 : undefined,
647→          resolvedBaseBranch,
648→        );
649→        results.push(result);
650→
651→        // Record PR info in log before completing issue
652→        if (logWriter && result.prNumber && result.prUrl) {
653→          logWriter.setPRInfo(result.prNumber, result.prUrl);
654→        }
655→
656→        // Complete issue logging
657→        if (logWriter) {
658→          logWriter.completeIssue();
659→        }
660→
661→        // Check if shutdown was triggered
662→        if (shutdown.shuttingDown) {
663→          break;
664→        }
665→
666→        if (!result.success) {
667→          // Check if QA gate is enabled and QA specifically failed
668→          if (mergedOptions.qaGate) {
669→            const qaResult = result.phaseResults.find((p) => p.phase === "qa");
670→            const qaFailed = qaResult && !qaResult.success;
671→
672→            if (qaFailed) {
673→              // QA gate: pause chain with clear messaging
674→              console.log(chalk.yellow("\n  ⏸️  QA Gate"));
675→              console.log(
676→                chalk.yellow(
677→                  `     Issue #${issueNumber} QA did not pass. Chain paused.`,
678→                ),
679→              );
680→              console.log(
681→                chalk.gray(
682→                  "     Fix QA issues and re-run, or run /loop to auto-fix.",
683→                ),
684→              );
685→
686→              // Update state to waiting_for_qa_gate
687→              if (stateManager) {
688→                try {
689→                  await stateManager.updateIssueStatus(
690→                    issueNumber,
691→                    "waiting_for_qa_gate",
692→                  );
693→                } catch {
694→                  // State tracking errors shouldn't stop execution
695→                }
696→              }
697→              break;
698→            }
699→          }
700→
701→          const chainInfo = mergedOptions.chain ? " (chain stopped)" : "";
702→          console.log(
703→            chalk.yellow(
704→              `\n  ⚠️  Issue #${issueNumber} failed, stopping sequential execution${chainInfo}`,
705→            ),
706→          );
707→          break;
708→        }
709→      }
710→    } else {
711→      // Default mode: run issues serially but continue on failure (don't stop)
712→      // TODO: Add proper parallel execution with listr2
713→      for (const issueNumber of issueNumbers) {
714→        // Check if shutdown was triggered
715→        if (shutdown.shuttingDown) {
716→          break;
717→        }
718→
719→        const issueInfo = issueInfoMap.get(issueNumber) ?? {
720→          title: `Issue #${issueNumber}`,
721→          labels: [],
722→        };
723→        const worktreeInfo = worktreeMap.get(issueNumber);
724→
725→        // Start issue logging
726→        if (logWriter) {
727→          logWriter.startIssue(issueNumber, issueInfo.title, issueInfo.labels);
728→        }
729→
730→        const result = await runIssueWithLogging(
731→          issueNumber,
732→          config,
733→          logWriter,
734→          stateManager,
735→          issueInfo.title,
736→          issueInfo.labels,
737→          mergedOptions,
738→          worktreeInfo?.path,
739→          worktreeInfo?.branch,
740→          shutdown,
741→          false, // Parallel mode doesn't support chain
742→          manifest.packageManager,
743→          undefined,
744→          resolvedBaseBranch,
745→        );
746→        results.push(result);
747→
748→        // Record PR info in log before completing issue
749→        if (logWriter && result.prNumber && result.prUrl) {
750→          logWriter.setPRInfo(result.prNumber, result.prUrl);
751→        }
752→
753→        // Complete issue logging
754→        if (logWriter) {
755→          logWriter.completeIssue();
756→        }
757→      }
758→    }
759→
760→    // Finalize log
761→    let logPath: string | null = null;
762→    if (logWriter) {
763→      logPath = await logWriter.finalize({
764→        endCommit: getCommitHash(process.cwd()),
765→      });
766→    }
767→
768→    // Calculate success/failure counts
769→    const passed = results.filter((r) => r.success).length;
770→    const failed = results.filter((r) => !r.success).length;
771→
772→    // Record metrics (local analytics)
773→    if (!config.dryRun && results.length > 0) {
774→      try {
775→        const metricsWriter = new MetricsWriter({ verbose: config.verbose });
776→
777→        // Calculate total duration
778→        const totalDuration = results.reduce(
779→          (sum, r) => sum + (r.durationSeconds ?? 0),
780→          0,
781→        );
782→
783→        // Get unique phases from all results
784→        const allPhases = new Set<MetricPhase>();
785→        for (const result of results) {
786→          for (const phaseResult of result.phaseResults) {
787→            // Only include phases that are valid MetricPhases
788→            const phase = phaseResult.phase as MetricPhase;
789→            if (
790→              [
791→                "spec",
792→                "security-review",
793→                "testgen",
794→                "exec",
795→                "test",
796→                "qa",
797→                "loop",
798→              ].includes(phase)
799→            ) {
800→              allPhases.add(phase);
801→            }
802→          }
803→        }
804→
805→        // Calculate aggregate metrics from worktrees
806→        let totalFilesChanged = 0;
807→        let totalLinesAdded = 0;
808→        let totalQaIterations = 0;
809→
810→        for (const result of results) {
811→          const worktreeInfo = worktreeMap.get(result.issueNumber);
812→          if (worktreeInfo?.path) {
813→            const stats = getWorktreeDiffStats(worktreeInfo.path);
814→            totalFilesChanged += stats.filesChanged;
815→            totalLinesAdded += stats.linesAdded;
816→          }
817→          // Count QA iterations (loop phases indicate retries)
818→          if (result.loopTriggered) {
819→            totalQaIterations += result.phaseResults.filter(
820→              (p) => p.phase === "loop",
821→            ).length;
822→          }
823→        }
824→
825→        // Build CLI flags for metrics
826→        const cliFlags: string[] = [];
827→        if (mergedOptions.sequential) cliFlags.push("--sequential");
828→        if (mergedOptions.chain) cliFlags.push("--chain");
829→        if (mergedOptions.qaGate) cliFlags.push("--qa-gate");
830→        if (mergedOptions.qualityLoop) cliFlags.push("--quality-loop");
831→        if (mergedOptions.testgen) cliFlags.push("--testgen");
832→
833→        // Read token usage from SessionEnd hook files (AC-5, AC-6)
834→        const tokenUsage = getTokenUsageForRun(undefined, true); // cleanup after reading
835→
836→        // Record the run
837→        await metricsWriter.recordRun({
838→          issues: issueNumbers,
839→          phases: Array.from(allPhases),
840→          outcome: determineOutcome(passed, results.length),
841→          duration: totalDuration,
842→          model: process.env.ANTHROPIC_MODEL ?? "opus",
843→          flags: cliFlags,
844→          metrics: {
845→            tokensUsed: tokenUsage.tokensUsed,
846→            filesChanged: totalFilesChanged,
847→            linesAdded: totalLinesAdded,
848→            acceptanceCriteria: 0, // Would need to parse from issue
849→            qaIterations: totalQaIterations,
850→            // Token breakdown (AC-6)
851→            inputTokens: tokenUsage.inputTokens || undefined,
852→            outputTokens: tokenUsage.outputTokens || undefined,
853→            cacheTokens: tokenUsage.cacheTokens || undefined,
854→          },
855→        });
856→
857→        if (config.verbose) {
858→          console.log(
859→            chalk.gray(`  📊 Metrics recorded to .sequant/metrics.json`),
860→          );
861→        }
862→      } catch (metricsError) {
863→        // Metrics recording errors shouldn't stop execution
864→        if (config.verbose) {
865→          console.log(
866→            chalk.yellow(`  ⚠️  Metrics recording error: ${metricsError}`),
867→          );
868→        }
869→      }
870→    }
871→
872→    // Summary
873→    console.log("\n" + ui.divider());
874→    console.log(colors.info("  Summary"));
875→    console.log(ui.divider());
876→
877→    console.log(
878→      colors.muted(
879→        `\n  Results: ${colors.success(`${passed} passed`)}, ${colors.error(`${failed} failed`)}`,
880→      ),
881→    );
882→
883→    for (const result of results) {
884→      const status = result.success
885→        ? ui.statusIcon("success")
886→        : ui.statusIcon("error");
887→      const duration = result.durationSeconds
888→        ? colors.muted(` (${formatDuration(result.durationSeconds)})`)
889→        : "";
890→      const phases = result.phaseResults
891→        .map((p) =>
892→          p.success ? colors.success(p.phase) : colors.error(p.phase),
893→        )
894→        .join(" → ");
895→      const loopInfo = result.loopTriggered ? colors.warning(" [loop]") : "";
896→      const prInfo = result.prUrl
897→        ? colors.muted(` → PR #${result.prNumber}`)
898→        : "";
899→      console.log(
900→        `  ${status} #${result.issueNumber}: ${phases}${loopInfo}${prInfo}${duration}`,
901→      );
902→    }
903→
904→    console.log("");
905→
906→    if (logPath) {
907→      console.log(colors.muted(`  📝 Log: ${logPath}`));
908→      console.log("");
909→    }
910→
911→    // Reflection analysis (--reflect flag)
912→    if (mergedOptions.reflect && results.length > 0) {
913→      const reflection = analyzeRun({
914→        results,
915→        issueInfoMap,
916→        runLog: logWriter?.getRunLog() ?? null,
917→        config: {
918→          phases: config.phases,
919→          qualityLoop: config.qualityLoop,
920→        },
921→      });
922→      const reflectionOutput = formatReflection(reflection);
923→      if (reflectionOutput) {
924→        console.log(reflectionOutput);
925→        console.log("");
926→      }
927→    }
928→
929→    // Suggest merge checks for multi-issue batches
930→    if (results.length > 1 && passed > 0 && !config.dryRun) {
931→      console.log(
932→        colors.muted("  💡 Verify batch integration before merging:"),
933→      );
934→      console.log(colors.muted("     sequant merge --check"));
935→      console.log("");
936→    }
937→
938→    if (config.dryRun) {
939→      console.log(
940→        colors.warning(
941→          "  ℹ️  This was a dry run. Use without --dry-run to execute.",
942→        ),
943→      );
944→      console.log("");
945→    }
946→
947→    // Set exit code if any failed
948→    if (failed > 0 && !config.dryRun) {
949→      exitCode = 1;
950→    }
951→  } finally {
952→    // Always dispose shutdown manager to clean up signal handlers
953→    shutdown.dispose();
954→  }
955→
956→  // Exit with error if any failed (outside try/finally so dispose() runs first)
957→  if (exitCode !== 0) {
958→    process.exit(exitCode);
959→  }
960→}
